// ============================================================================
// SECTION 1: VALIDATE INPUT FOR QC CONTEXT BUILDER v2.0
// ============================================================================

const rawInput = $input.first().json;

console.log("=== QC CONTEXT BUILDER v2.0 - WEBHOOK INPUT ===");
console.log("Keys:", Object.keys(rawInput));

// Extract from body if needed
let input = {};
if (rawInput.body && typeof rawInput.body === 'string') {
  try {
    input = JSON.parse(rawInput.body.trim().replace(/^=/, ''));
  } catch (e) {
    console.log("Failed to parse body:", e.message);
  }
} else if (rawInput.body && typeof rawInput.body === 'object') {
  input = rawInput.body;
} else {
  input = rawInput;
}

console.log("Extracted input:", JSON.stringify(input));

// ============================================================================
// SECTION 2: VALIDATE REQUIRED FIELDS
// ============================================================================

if (!input.contractId) {
  throw new Error('contractId is required');
}

const validRoles = ['initiator', 'respondent'];
if (!validRoles.includes(input.viewerRole)) {
  throw new Error(`viewerRole must be 'initiator' or 'respondent'. Received: '${input.viewerRole}'`);
}

// Parse touchpointContext if string
if (input.touchpointContext && typeof input.touchpointContext === 'string') {
  try {
    input.touchpointContext = JSON.parse(input.touchpointContext);
  } catch (e) {
    input.touchpointContext = {};
  }
}

// ============================================================================
// SECTION 3: NORMALIZE OUTPUT
// ============================================================================

const validated = {
  contractId: input.contractId,
  viewerRole: input.viewerRole,
  viewerUserId: input.viewerUserId || '',
  viewerCompanyId: input.viewerCompanyId || '',
  touchpointType: input.touchpointType || 'qc_chat',
  touchpointContext: input.touchpointContext || {},
  clauseId: input.touchpointContext?.clauseId || input.clauseId || '',
  userMessage: input.touchpointContext?.userMessage || input.userMessage || '',
  // NEW v2.0: Role matrix fields forwarded from API route
  contractTypeKey: input.contractTypeKey || '',
  initiatorPartyRole: input.initiatorPartyRole || '',
  buildStartedAt: Date.now()
};

console.log("=== QC CONTEXT BUILDER v2.0 VALIDATED ===");
console.log("Contract:", validated.contractId);
console.log("Viewer:", validated.viewerRole);
console.log("Touchpoint:", validated.touchpointType);
console.log("ClauseId:", validated.clauseId);
console.log("ContractTypeKey:", validated.contractTypeKey);
console.log("InitiatorPartyRole:", validated.initiatorPartyRole);

return [{ json: validated }];

// ============================================================================
// ASSEMBLE QC CONTEXT OBJECT v2.0
// ============================================================================
// Changes from v1.0:
// - Added contract_type_key and initiator_party_role to contract overview
// - Added position_labels (from clause_range_mappings) to clause data
// - Fixed alignment terminology: leverageBalance vs clauseAlignment
// - Added viewerAnchoring section for prompt builder
// ============================================================================

const input = $("Validate Input").first().json;
const contract = $("Fetch Contract Info").first()?.json || {};
const clauseStats = $("Fetch Clause Stats").first()?.json || {};
const allClauses =
  $("Fetch All Clauses")
    .all()
    .map((i) => i.json) || [];
const activityEvents =
  $("Fetch Activity Events")
    .all()
    .map((i) => i.json) || [];
const partyChat =
  $("Fetch Party Chat")
    .all()
    .map((i) => i.json) || [];
const playbook = $("Fetch Company Playbook").first()?.json || null;

// Get specific clause if available (from conditional branch)
let specificClause = null;
let clauseEvents = [];
try {
  specificClause = $("Fetch Specific Clause").first()?.json || null;
  clauseEvents =
    $("Fetch Clause Events")
      .all()
      .map((i) => i.json) || [];
} catch (e) {
  // Clause-specific nodes didn't run
}

// ============================================================================
// BUILD CONTEXT SECTIONS
// ============================================================================

// 1. CONTRACT OVERVIEW — v2.0: includes contract_type_key, initiator_party_role
const contractOverview = {
  contractId: contract.contract_id,
  contractName: contract.contract_name,
  contractType: contract.contract_type || "Contract",
  contractTypeKey: contract.contract_type_key || null,
  initiatorPartyRole: contract.initiator_party_role || null,
  status: contract.contract_status,
  createdAt: contract.contract_created_at,
  initiator: {
    name: contract.initiator_name,
    email: contract.initiator_email,
    company: contract.initiator_company,
  },
  respondent: {
    name: contract.respondent_name,
    email: contract.respondent_email,
    company: contract.respondent_company,
    status: contract.respondent_status,
    accessedAt: contract.respondent_accessed_at,
  },
};

// 2. CLAUSE STATISTICS — v2.0: disambiguated alignment terminology
const statistics = {
  totalClauses: clauseStats.total_clauses || 0,
  certifiedClauses: clauseStats.certified_clauses || 0,
  negotiableClauses: clauseStats.negotiable_clauses || 0,
  avgClarencePosition: clauseStats.avg_clarence_position,
  balancedCount: clauseStats.balanced_count || 0,
  reviewNeededCount: clauseStats.review_needed_count || 0,
  clausesWithAgreements: clauseStats.clauses_with_agreements || 0,
  pendingQueries: clauseStats.pending_queries || 0,
  // v2.0: Disambiguated alignment - NEVER call both 'alignment'
  clauseAlignment: clauseStats.clauses_with_agreements > 0
    ? Math.round((clauseStats.clauses_with_agreements / Math.max(clauseStats.negotiable_clauses, 1)) * 100)
    : 0,
};

// 3. CLAUSES SUMMARY — v2.0: includes position_labels from range_mappings
const clausesWithGaps = allClauses
  .filter((c) => c.position_gap !== null && c.position_gap > 0)
  .sort((a, b) => b.position_gap - a.position_gap)
  .slice(0, 5)
  .map((c) => ({
    ...c,
    positionLabels: c.position_labels || null,
    valueType: c.value_type || null,
    rangeUnit: c.range_unit || null,
  }));

const flaggedClauses = allClauses
  .filter((c) => c.clarence_flags && c.clarence_flags.length > 0)
  .slice(0, 5);

const reviewNeededClauses = allClauses
  .filter((c) => c.clarence_fairness && c.clarence_fairness !== "balanced")
  .slice(0, 5);

// 4. RECENT ACTIVITY (formatted for context)
const recentActivity = activityEvents.slice(0, 10).map((e) => ({
  type: e.event_type,
  party: e.party_role,
  actor: e.user_name,
  summary: e.activity_summary,
  clauseId: e.clause_id,
  timestamp: e.created_at,
}));

// 5. PARTY CHAT (formatted for context)
const recentPartyChat = partyChat.slice(0, 10).map((m) => ({
  sender: m.sender_name,
  role: m.sender_role,
  message: m.message_text?.substring(0, 300),
  relatedClause: m.related_clause_name,
  isSystem: m.is_system_message,
  timestamp: m.created_at,
}));

// 6. SPECIFIC CLAUSE CONTEXT — v2.0: includes position_labels
let clauseContext = null;
if (specificClause) {
  clauseContext = {
    clauseId: specificClause.clause_id,
    clauseNumber: specificClause.clause_number,
    clauseName: specificClause.clause_name,
    category: specificClause.category,
    fullText: specificClause.full_clause_text,
    originalText: specificClause.original_text,
    draftText: specificClause.draft_text,
    clarencePosition: specificClause.clarence_position,
    clarenceFairness: specificClause.clarence_fairness,
    clarenceSummary: specificClause.clarence_summary,
    clarenceAssessment: specificClause.clarence_assessment,
    clarenceFlags: specificClause.clarence_flags || [],
    initiatorPosition: specificClause.initiator_position,
    respondentPosition: specificClause.respondent_position,
    extractedValue: specificClause.extracted_value,
    extractedUnit: specificClause.extracted_unit,
    valueType: specificClause.value_type,
    // v2.0: Position labels from clause_range_mappings
    positionLabels: specificClause.position_labels || null,
    rangeValueType: specificClause.range_value_type || null,
    rangeUnit: specificClause.range_unit || null,
    recentEvents: clauseEvents.slice(0, 5).map((e) => ({
      type: e.event_type,
      party: e.party_role,
      actor: e.user_name,
      summary: e.activity_summary,
      timestamp: e.created_at,
    })),
  };
}

// 7. COMPANY PLAYBOOK (if available)
let playbookContext = null;
if (playbook && playbook.playbook_id) {
  playbookContext = {
    playbookName: playbook.playbook_name,
    description: playbook.playbook_description,
    defaultStance: playbook.default_stance,
    riskTolerance: playbook.risk_tolerance,
    relationshipPriority: playbook.relationship_priority,
    activeRules: playbook.active_rules || [],
  };
}

// ============================================================================
// 8. VIEWER ANCHORING — v2.0: NEW
// Pre-compute viewer-specific labels so the prompt builder doesn't have to
// ============================================================================

const isInitiator = input.viewerRole === 'initiator';
const viewerAnchoring = {
  viewerRole: input.viewerRole,
  viewerName: isInitiator ? contractOverview.initiator.name : contractOverview.respondent.name,
  viewerCompany: isInitiator ? contractOverview.initiator.company : contractOverview.respondent.company,
  otherPartyName: isInitiator ? contractOverview.respondent.name : contractOverview.initiator.name,
  otherPartyCompany: isInitiator ? contractOverview.respondent.company : contractOverview.initiator.company,
  // These will be overridden by roleContext from the API route if available
  viewerRoleLabel: null,
  otherPartyRoleLabel: null,
};

// ============================================================================
// FINAL CONTEXT OBJECT
// ============================================================================

const qcContext = {
  contextType: "qc_studio",
  contextVersion: "2.0",
  buildTimestamp: new Date().toISOString(),
  buildDurationMs: Date.now() - input.buildStartedAt,

  // Request metadata
  request: {
    contractId: input.contractId,
    viewerRole: input.viewerRole,
    viewerUserId: input.viewerUserId,
    touchpointType: input.touchpointType,
    userMessage: input.userMessage,
  },

  // v2.0: Viewer anchoring data
  viewerAnchoring: viewerAnchoring,

  // Core context sections
  contract: contractOverview,
  statistics: statistics,

  // Clause analysis — v2.0: includes position_labels
  clauseHighlights: {
    biggestGaps: clausesWithGaps,
    flaggedClauses: flaggedClauses,
    reviewNeeded: reviewNeededClauses,
  },

  // Communication history
  recentActivity: recentActivity,
  partyChat: recentPartyChat,

  // Specific clause (if requested) — v2.0: includes position_labels
  clauseContext: clauseContext,

  // Company guidance
  playbook: playbookContext,
};

console.log("=== QC CONTEXT v2.0 BUILT ===");
console.log("Contract:", qcContext.contract.contractName);
console.log("Contract Type Key:", qcContext.contract.contractTypeKey);
console.log("Clauses:", qcContext.statistics.totalClauses);
console.log("Clause Alignment:", qcContext.statistics.clauseAlignment + '%');
console.log("Activity Events:", qcContext.recentActivity.length);
console.log("Party Chat:", qcContext.partyChat.length);
console.log("Has Clause Context:", !!qcContext.clauseContext);
console.log("Has Position Labels:", !!qcContext.clauseContext?.positionLabels);
console.log("Has Playbook:", !!qcContext.playbook);
console.log("Viewer:", qcContext.viewerAnchoring.viewerName, '(' + qcContext.viewerAnchoring.viewerRole + ')');
console.log("Build Time:", qcContext.buildDurationMs, "ms");

return [{ json: qcContext }];
